  ('medical-tech-moex-15414', 'medical-tech', 'medical-tech-moex-099-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '某病人血漿中含有抗體，對所有血袋、抗體鑑定Panel cells、抗體篩檢細胞等均有反應。則最有可能 取得相容血液的來源為：', '["祖父母", "父母", "兄弟姐妹", "配偶"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "342bf420f9c6", "answer_pdf_sha1": "5892de59bac6", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "104", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 76, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15415', 'medical-tech', 'medical-tech-moex-099-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '下列有關anti-U的敘述，何者錯誤？', '["為臨床有意義的抗體", "只見於非裔黑人", "只見於(S-s-)表現型的人", "見於Fy(a-b-)表現型的人"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "342bf420f9c6", "answer_pdf_sha1": "5892de59bac6", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "104", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 77, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15416', 'medical-tech', 'medical-tech-moex-099-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '某56歲病人因尿道感染依醫師處方服用ceftriaxone。第四天病人因倦怠及深茶色尿再度就醫。病人 血色素7.5 gm/dL，DAT為陽性(2+)，anti-IgG(2+)及anti-C3(1+)，但抗體篩檢為陰性。下列有關其 溶血機制的敘述，何者錯誤？', '["病人可能為藥物引起紅血球上非特異性的免疫球蛋白吸附", "可能的機制為藥物及藥物抗體免疫複合物引起的溶血反應", "可能的機制為藥物吸附至紅血球，因藥物抗體引起溶血反應", "可能因藥物關係引起自體抗體相關的溶血反應，與藥物抗體無關"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "342bf420f9c6", "answer_pdf_sha1": "5892de59bac6", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "104", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 78, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-15417', 'medical-tech', 'medical-tech-moex-099-9168e375', 'sub-medical-tech-03', NULL, 'single_choice', '下列有關Glycophorin A（GPA）之敘述，何者錯誤？', '["蛋白鏈上具有許多經O聯結（O-link）的醣分子，係一種醣蛋白", "為紅血球負電荷的主要來源", "GPA上的抗原易受酵素破壞", "會被硫還原劑（Thio-reducing agent）破壞"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:02+00:00", "source_pdf_sha1": "342bf420f9c6", "answer_pdf_sha1": "5892de59bac6", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "104", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血液學與血庫學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 79, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
